generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor on the motor measuring motor current (IM)"
    DTDFVocab:producedData MotorCurrentTransmission
]

instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder directly on the motor measuring motor angle (θM)"
    DTDFVocab:producedData MotorAngleTransmission
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder behind the gearbox measuring gearbox angle (θG)"
    DTDFVocab:producedData GearboxAngleTransmission
]

// C4: Physical-to-virtual interaction
instance MotorCurrentTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorAngleTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxAngleTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

// C10: Models/Data
instance SysMLStructuralModel : DTDFVocab:Model [
    base:desc "Structural engineering model in SysML representing motor and gearboxes"
    DTDFVocab:inputTo SimulinkEngine
]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "Simulink model of the motor component"
    DTDFVocab:inputTo SimulinkEngine
]

instance SimulinkGearwheelModel : DTDFVocab:Model [
    base:desc "Simulink model of the gearwheel component"
    DTDFVocab:inputTo SimulinkEngine
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "Simulink model of the gearbox component"
    DTDFVocab:inputTo SimulinkEngine
]

// Data traces
instance MotorCurrentTrace : DTDFVocab:Data [
    base:desc "Trace of motor current (IM) received from MQTT"
    DTDFVocab:inputTo DataProcessingEngine
    DTDFVocab:fromData MotorCurrentTransmission
]

instance MotorAngleTrace : DTDFVocab:Data [
    base:desc "Trace of motor angle (θM) received from MQTT"
    DTDFVocab:inputTo DataProcessingEngine
    DTDFVocab:fromData MotorAngleTransmission
]

instance GearboxAngleTrace : DTDFVocab:Data [
    base:desc "Trace of gearbox angle (θG) received from MQTT"
    DTDFVocab:inputTo DataProcessingEngine
    DTDFVocab:fromData GearboxAngleTransmission
]

instance TorqueMTrace : DTDFVocab:Data [
    base:desc "Derived motor torque (τM) calculated from current and angle"
    DTDFVocab:inputTo DataProcessingEngine
]

instance TorqueGTrace : DTDFVocab:Data [
    base:desc "Derived gearbox torque (τG) calculated from motor torque and gear ratio"
    DTDFVocab:inputTo DataProcessingEngine
]

instance TorqueOutTrace : DTDFVocab:Data [
    base:desc "Derived output torque (τout) after gearbox"
    DTDFVocab:inputTo DataProcessingEngine
]

instance AngularVelocityMTrace : DTDFVocab:Data [
    base:desc "Derived motor angular velocity (ωM) from angle measurements"
    DTDFVocab:inputTo DataProcessingEngine
]

instance AngularVelocityGTrace : DTDFVocab:Data [
    base:desc "Derived gearbox angular velocity (ωG) from motor velocity and gear ratio"
    DTDFVocab:inputTo DataProcessingEngine
]

instance AngularVelocityOutTrace : DTDFVocab:Data [
    base:desc "Derived output angular velocity (ωout) of the joint"
    DTDFVocab:inputTo DataProcessingEngine
]

instance AccelerationTrace : DTDFVocab:Data [
    base:desc "Derived angular acceleration from velocity data"
    DTDFVocab:inputTo DataProcessingEngine
]

// C11: Enablers
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker for real-time, one-way data ingestion from robot sensors"
    DTDFVocab:enables FrictionIdentificationService
]

instance SimulinkEngine : DTDFVocab:Enabler [
    base:desc "Simulink engine executing motor, gearwheel, and gearbox models for simulation"
    DTDFVocab:enables VisualizationDashboardService
]

instance DataProcessingEngine : DTDFVocab:Enabler [
    base:desc "Processing component for data calculation and simulation of joint dynamics"
    DTDFVocab:enables FrictionIdentificationService
]

// C6: Services
instance VisualizationDashboardService : DTDFVocab:Service [
    base:desc "Provides a visualization dashboard displaying measured and simulated data traces"
    DTDFVocab:provides DashboardVisualizationInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Identifies joint friction models using white-box (Coulomb-Viscous, Stribeck, Dahl, LuGre) and black-box models"
    DTDFVocab:provides FrictionLossInsight, MotionControlParamUpdateAction
]

// C17: Insights/Actions
instance DashboardVisualizationInsight : DTDFVocab:Insight [
    base:desc "Visualization of measured and simulated data traces for the first axis"
]

instance FrictionLossInsight : DTDFVocab:Insight [
    base:desc "Quantitative assessment of friction loss in the first vertical axis"
]

instance MotionControlParamUpdateAction : DTDFVocab:Action [
    base:desc "Automatically updates motion-control parameters based on refined friction model"
    DTDFVocab:IsAutomatic true
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time data streaming; the digital shadow processes data as soon as it arrives (no explicit sample rate is specified)."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Comprises the digital shadow (data traces, structural and simulation models), a processing component that consumes sensor data and produces simulated traces, an Asset Administration Shell describing the robot asset, and a dashboard for user interaction. The system is organized with clear associations via the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design phase: creation of structural and simulation models in SysML and Simulink. Manufacturing phase: asset description via Asset Administration Shell. Operation phase: real‑time data collection and continuous friction model identification, with the digital shadow being refined during robot operation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "All data traces maintain traceability to processing components and models through originates‑from associations. Simulation models are validated against measured sensor data; continuous friction parameter identification mitigates uncertainties. Verification checks include comparing simulated versus measured data to detect discrepancies."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "One‑way MQTT streaming from the robot to the digital shadow. Data includes sensor measurements; MQTT topics provide a standard publish/subscribe mechanism for real‑time data transfer."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Employs the Asset Administration Shell (AAS) standard for asset description and uses SysML for modeling, following MBSE best practices and industry standards."
]
